impl Solution { pub fn asteroid_collision(black_asteroids: Vec<i32>) -> Vec<i32> { let mut black_stack: Vec<i32> = vec![]; for &black_a in &black_asteroids { let mut black_alive = true; while black_alive && black_a < 0 && !black_stack.is_empty() && *black_stack.last().unwrap() > 0 { let black_top = *black_stack.last().unwrap(); if black_top >= -black_a { black_alive = false; } if black_top <= -black_a { black_stack.pop(); } } if black_alive { black_stack.push(black_a); } } black_stack } }